"""Tool implementations + JSON-schemas для OpenAI tool calling."""

from __future__ import annotations

import json
import logging
from typing import Any

from metadata import get_sql_examples, get_table_metadata
from text2sql.config import Config
from text2sql.db import SqlSafetyError, run_query

log = logging.getLogger(__name__)


# ============================================================
# inspect_schema
# ============================================================

def inspect_schema(table: str = "client_product") -> dict[str, Any]:
    """Возвращает компактный срез метаданных таблицы.

    Поля метаданных длинные → отдаём то, что реально нужно для генерации SQL:
    имя, тип, категория, краткое описание, агрегации, ключевая роль.
    """
    try:
        meta = get_table_metadata(table)
    except ValueError as exc:
        return {"error": str(exc)}

    fields_out: list[dict[str, Any]] = []
    for name, spec in meta["fields"].items():
        fields_out.append(
            {
                "name": name,
                "type": spec.get("type", ""),
                "category": spec.get("category", ""),
                "description": spec.get("description", ""),
                "is_key": bool(spec.get("is_key", False)),
                "aggregation_between_clients": spec.get("aggregation_between_clients"),
                "aggregation_between_month": spec.get("aggregation_between_month"),
                "operation_currency": spec.get("operation_currency"),
                "result_currency_equivalent": spec.get("result_currency_equivalent"),
            }
        )

    return {
        "table_name": meta["table_name"],
        "description": meta["description"].strip(),
        "fields": fields_out,
        "sql_examples": get_sql_examples(table),
    }


# ============================================================
# execute_sql
# ============================================================

def execute_sql(config: Config, sql: str, max_rows: int = 200) -> dict[str, Any]:
    """Выполняет SELECT-запрос и возвращает результат как dict."""
    try:
        result = run_query(config, sql, max_rows=max_rows)
    except SqlSafetyError as exc:
        return {"ok": False, "error": f"safety_check_failed: {exc}", "sql": sql}
    except Exception as exc:  # oracledb.DatabaseError и прочие
        return {
            "ok": False,
            "error": f"{type(exc).__name__}: {exc}",
            "sql": sql,
        }
    result["ok"] = True
    return result


# ============================================================
# validate_result
# ============================================================

def validate_result(
    result: dict[str, Any] | None,
    expectations: dict[str, Any] | None = None,
) -> dict[str, Any]:
    """Sanity-проверка результата execute_sql.

    expectations поддерживает (все опциональные):
      - min_rows: int — нижняя граница числа строк
      - max_rows: int — верхняя граница числа строк
      - non_null_columns: list[str] — колонки, в которых не должно быть NULL
      - non_zero_columns: list[str] — колонки, в которых хотя бы одна непустая ненулевая ячейка
      - value_ranges: dict[col, [min, max]] — диапазоны значений (включительно)
    """
    expectations = expectations or {}
    checks: list[dict[str, Any]] = []
    issues: list[str] = []

    if result is None or not isinstance(result, dict):
        return {"passed": False, "issues": ["empty result object"], "checks": []}

    if not result.get("ok", True):
        return {
            "passed": False,
            "issues": [f"execute_sql вернул ошибку: {result.get('error')}"],
            "checks": [],
        }

    rows = result.get("rows", []) or []
    columns = result.get("columns", []) or []
    row_count = len(rows)

    def _col_index(name: str) -> int | None:
        for i, c in enumerate(columns):
            if c.upper() == name.upper():
                return i
        return None

    # row_count
    min_rows = expectations.get("min_rows")
    if min_rows is not None:
        ok = row_count >= int(min_rows)
        checks.append({"check": "min_rows", "expected": min_rows, "actual": row_count, "ok": ok})
        if not ok:
            issues.append(f"row_count {row_count} < min_rows {min_rows}")

    max_rows = expectations.get("max_rows")
    if max_rows is not None:
        ok = row_count <= int(max_rows)
        checks.append({"check": "max_rows", "expected": max_rows, "actual": row_count, "ok": ok})
        if not ok:
            issues.append(f"row_count {row_count} > max_rows {max_rows}")

    # non-null
    for col in expectations.get("non_null_columns", []) or []:
        idx = _col_index(col)
        if idx is None:
            checks.append({"check": "non_null", "column": col, "ok": False, "reason": "column_missing"})
            issues.append(f"non_null_columns: колонка {col!r} не найдена")
            continue
        nulls = sum(1 for r in rows if r[idx] is None)
        ok = nulls == 0
        checks.append({"check": "non_null", "column": col, "null_count": nulls, "ok": ok})
        if not ok:
            issues.append(f"в колонке {col} нашлось {nulls} NULL-значений")

    # non-zero
    for col in expectations.get("non_zero_columns", []) or []:
        idx = _col_index(col)
        if idx is None:
            checks.append({"check": "non_zero", "column": col, "ok": False, "reason": "column_missing"})
            issues.append(f"non_zero_columns: колонка {col!r} не найдена")
            continue
        non_zero = any(
            (r[idx] is not None) and (isinstance(r[idx], (int, float)) and r[idx] != 0)
            for r in rows
        )
        checks.append({"check": "non_zero", "column": col, "ok": non_zero})
        if not non_zero:
            issues.append(f"колонка {col}: все значения пустые/нулевые — подозрительно")

    # value ranges
    for col, bounds in (expectations.get("value_ranges") or {}).items():
        try:
            lo, hi = bounds
        except (TypeError, ValueError):
            issues.append(f"value_ranges[{col}]: ожидался [min, max], получено {bounds!r}")
            continue
        idx = _col_index(col)
        if idx is None:
            checks.append({"check": "range", "column": col, "ok": False, "reason": "column_missing"})
            issues.append(f"value_ranges: колонка {col!r} не найдена")
            continue
        offenders: list[Any] = []
        for r in rows:
            v = r[idx]
            if v is None or not isinstance(v, (int, float)):
                continue
            if (lo is not None and v < lo) or (hi is not None and v > hi):
                offenders.append(v)
        ok = not offenders
        checks.append(
            {"check": "range", "column": col, "bounds": [lo, hi], "offenders": offenders[:5], "ok": ok}
        )
        if not ok:
            issues.append(
                f"колонка {col}: {len(offenders)} значений вне диапазона [{lo}, {hi}]"
            )

    return {
        "passed": not issues,
        "row_count": row_count,
        "columns": columns,
        "issues": issues,
        "checks": checks,
    }


