def dispatch(name: str, args: dict[str, Any], *, config: Config, last_result: dict[str, Any] | None) -> Any:
    """Маршрутизация вызова tool по имени. Возвращает результат, который пойдёт в LLM."""
    if name == "inspect_schema":
        return inspect_schema(args.get("table") or "client_product")
    if name == "execute_sql":
        sql = args.get("sql") or ""
        return execute_sql(config, sql)
    if name == "validate_result":
        # Используем последний результат execute_sql, который агент видел.
        return validate_result(last_result, args.get("expectations") or {})
    if name == "final_answer":
        # final_answer обрабатывается в самом цикле агента — сюда попадать не должно,
        # но если попало — просто эхо.
        return {"text": args.get("text", ""), "supporting_data": args.get("supporting_data")}
    return {"error": f"unknown tool: {name}"}


def safe_dump(obj: Any, max_chars: int = 12_000) -> str:
    """Сериализация для отправки результата tool обратно в LLM. Обрезаем гигантские пейлоады."""
    try:
        s = json.dumps(obj, ensure_ascii=False, default=str)
    except (TypeError, ValueError):
        s = json.dumps(str(obj), ensure_ascii=False)
    if len(s) > max_chars:
        s = s[:max_chars] + "...<truncated>"
    return s

"""Обёртка над oracledb для выполнения SELECT-запросов."""

from __future__ import annotations

import contextlib
import datetime as _dt
import decimal
import re
from typing import Any, Iterator

import oracledb

from text2sql.config import Config


# Только SELECT и WITH (CTE) разрешены. Любые DDL/DML блокируются.
_ALLOWED_PREFIXES = ("select", "with")
# Запрет на множественные statement'ы и опасные конструкции.
_FORBIDDEN_TOKENS = re.compile(
    r"\b(insert|update|delete|drop|truncate|alter|create|grant|revoke|merge|"
    r"call|begin|exec|execute|commit|rollback)\b",
    flags=re.IGNORECASE,
)


class SqlSafetyError(ValueError):
    """SQL не прошёл safety-check."""


def assert_select_only(sql: str) -> str:
    """Возвращает нормализованный SQL или бросает SqlSafetyError."""
    if not sql or not sql.strip():
        raise SqlSafetyError("Пустой SQL")
    cleaned = sql.strip().rstrip(";").strip()
    # Сразу запрещаем несколько statement'ов.
    if ";" in cleaned:
        raise SqlSafetyError("Несколько statement'ов в одном запросе запрещено")
    lower = cleaned.lower()
    if not lower.startswith(_ALLOWED_PREFIXES):
        raise SqlSafetyError(
            "Разрешены только SELECT/WITH-запросы; получено: "
            f"{lower.split()[0] if lower.split() else '<empty>'}"
        )
    if _FORBIDDEN_TOKENS.search(lower):
        raise SqlSafetyError("SQL содержит запрещённые DDL/DML-конструкции")
    return cleaned


def _coerce(value: Any) -> Any:
    """Приводит значения Oracle к JSON-сериализуемым типам."""
    if value is None:
        return None
    if isinstance(value, (str, int, float, bool)):
        return value
    if isinstance(value, decimal.Decimal):
        # Decimal с дробной частью → float, целое → int.
        if value == value.to_integral_value():
            return int(value)
        return float(value)
    if isinstance(value, (_dt.datetime, _dt.date)):
        return value.isoformat()
    if isinstance(value, bytes):
        return value.decode("utf-8", errors="replace")
    return str(value)


@contextlib.contextmanager
def _connect(config: Config) -> Iterator[oracledb.Connection]:
    conn = oracledb.connect(
        user=config.oracle_username,
        password=config.oracle_password,
        dsn=config.oracle_dsn,
    )
    try:
        yield conn
    finally:
        with contextlib.suppress(Exception):
            conn.close()


def run_query(
    config: Config,
    sql: str,
    *,
    max_rows: int = 200,
) -> dict[str, Any]:
    """Выполняет SELECT-запрос и возвращает результат как словарь.

    Возвращает: {"columns": [...], "rows": [[...]], "row_count": N, "truncated": bool}.
    """
    cleaned = assert_select_only(sql)
    with _connect(config) as conn:
        with conn.cursor() as cur:
            cur.execute(cleaned)
            columns = [d[0] for d in (cur.description or [])]
            rows_raw = cur.fetchmany(max_rows + 1)
            truncated = len(rows_raw) > max_rows
            rows = [[_coerce(v) for v in row] for row in rows_raw[:max_rows]]
    return {
        "columns": columns,
        "rows": rows,
        "row_count": len(rows),
        "truncated": truncated,
        "sql": cleaned,
    }

