# --- Helpers для мок-OpenAI клиента --------------------------------------

@dataclass
class _Fn:
    name: str
    arguments: str


@dataclass
class _ToolCall:
    id: str
    function: _Fn
    type: str = "function"


@dataclass
class _Msg:
    content: str | None
    tool_calls: list[_ToolCall] | None


@dataclass
class _Choice:
    message: _Msg


@dataclass
class _Resp:
    choices: list[_Choice]


def _make_response(*, content: str | None = None, tool_calls: list[dict[str, Any]] | None = None) -> _Resp:
    tcs = None
    if tool_calls:
        tcs = [
            _ToolCall(
                id=tc.get("id", f"call_{i}"),
                function=_Fn(name=tc["name"], arguments=json.dumps(tc.get("args", {}))),
            )
            for i, tc in enumerate(tool_calls)
        ]
    return _Resp(choices=[_Choice(message=_Msg(content=content, tool_calls=tcs))])


class _FakeCompletions:
    def __init__(self, responses: list[_Resp]):
        self._responses = list(responses)
        self.calls: list[dict[str, Any]] = []

    def create(self, **kwargs: Any) -> _Resp:
        self.calls.append(kwargs)
        if not self._responses:
            raise AssertionError("FakeLLM: ответы кончились, агент позвал ещё раз")
        return self._responses.pop(0)


class _FakeChat:
    def __init__(self, responses: list[_Resp]):
        self.completions = _FakeCompletions(responses)


class _FakeClient:
    def __init__(self, responses: list[_Resp]):
        self.chat = _FakeChat(responses)


