def test_happy_path_inspect_execute_validate_final():
    """Полный happy-path: schema → SQL → validate → final."""
    fake_rows = {
        "ok": True,
        "columns": ["TOTAL"],
        "rows": [[123_456]],
        "row_count": 1,
        "truncated": False,
        "sql": "select sum(pnl_sum) from client_product",
    }
    responses = [
        _make_response(tool_calls=[{"name": "inspect_schema", "args": {}}]),
        _make_response(
            tool_calls=[
                {"name": "execute_sql", "args": {"sql": "select sum(pnl_sum) from client_product"}}
            ]
        ),
        _make_response(
            tool_calls=[
